const e={maxFlow:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Finde den höchsten volumetrischen Fluss (mm³/s), den dein Hotend dauerhaft halten kann — indem der Fluss schrittweise erhöht wird, während die StallGuard-Last des Extruders auf den Moment des Durchrutschens beobachtet wird. Sieh dir zuerst den Plan an; der Live-Test heizt und extrudiert, also bereite den Drucker vor dem Start vor."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über Max-Flow"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Verwendung"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Stelle die Testtemperatur und deinen Filamentdurchmesser ein (wähle ein Hotend zum Vorbelegen)."}},{t:0,b:{t:2,i:[{t:3}],s:"Zeige den Plan an — er listet jeden Flussschritt und wie viel Filament dabei gefördert wird."}},{t:0,b:{t:2,i:[{t:3}],s:"Hake die Sicherheits-Checkliste ab und starte dann den Live-Test (heizt + extrudiert)."}},{t:0,b:{t:2,i:[{t:3}],s:"Lies den maximal gehaltenen Fluss ab und übernimm den vorgeschlagenen Slicer-Wert."}}],topics:{howItWorks:{title:{t:0,b:{t:2,i:[{t:3}],s:"So funktioniert der Test"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Der Extruder fördert Filament mit stetig steigendem volumetrischen Fluss. Solange das gehärtete Förderrad sauber greift, bleibt der StallGuard-Lastwert eng beieinander; sobald es zu rutschen beginnt, springen die Werte stark. Der höchste Fluss vor diesem Sprung ist dein dauerhaft haltbarer Maximalfluss. Die Rampe stoppt, sobald Durchrutschen erkannt wird, sodass kein Filament über das erste Durchrutschen hinaus abgeschliffen wird."}}},stallguard:{title:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard-Schlupferkennung"}},body:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard ist eine Funktion des TMC-Treibers, die die Motorlast meldet. Dieser Test misst sie viele Male pro Flussschritt und sucht nach einem plötzlichen Anstieg der Streuung (IQR) oder Variation (CV) — dem typischen Zeichen, dass das Rad den Halt verliert. Die Schwellenwerte stammen aus einem treiberspezifischen Profil. Hinweis: Bei einem TMC2209-Extruder wird der experimentelle SG4-Pfad genutzt, betrachte den ersten Durchlauf daher als Kalibrierung."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Sicherheit"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Dies ist ein heißer, bewegter Test, der den Extruder absichtlich zum Durchrutschen bringt. Lade Filament, stelle sicher, dass die Düse frei ist (über dem Bett oder einem Abfallbereich) und bleibe in der Nähe. Der Durchlauf wird verweigert, während der Drucker druckt, und das Heizelement wird am Ende immer ausgeschaltet."}}},slicer:{title:{t:0,b:{t:2,i:[{t:3}],s:"Das Ergebnis nutzen"}},body:{t:0,b:{t:2,i:[{t:3}],s:'Trage den vorgeschlagenen Wert in den "max volumetric speed" deines Slicers ein (pro Filament). Der konservative Wert (80 % des gemessenen Maximums) ist eine sichere Alltagsgrenze; der ausgewogene Wert (90 %) reizt es etwas weiter aus. Höhere Hotend-Temperaturen erhöhen in der Regel den erreichbaren Fluss.'}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{flow:{term:{t:0,b:{t:2,i:[{t:3}],s:"Volumetrischer Fluss"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wie viel Kunststoff das Hotend pro Sekunde schmilzt (mm³/s) — das eigentliche Tempolimit für schnelles Drucken."}}},stallguard:{term:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein Signal des TMC-Treibers, das die mechanische Motorlast meldet und hier zum Erkennen des Extruder-Schlupfs verwendet wird."}}},slip:{term:{t:0,b:{t:2,i:[{t:3}],s:"Durchrutschen"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wenn das Extruderrad das Filament nicht mehr schnell genug greifen kann und überspringt — die Flussobergrenze."}}},meltzone:{term:{t:0,b:{t:2,i:[{t:3}],s:"Schmelzzone"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Die beheizte Länge des Hotends; eine längere Schmelzzone (z. B. Volcano) hält einen höheren Fluss."}}}}},params:{title:{t:0,b:{t:2,i:[{t:3}],s:"Testparameter"}},temperature:{t:0,b:{t:2,i:[{t:3}],s:"Temperatur (°C)"}},filamentDiameter:{t:0,b:{t:2,i:[{t:3}],s:"Filament-Ø (mm)"}},hotend:{t:0,b:{t:2,i:[{t:3}],s:"Hotend (optional)"}},hotendNone:{t:0,b:{t:2,i:[{t:3}],s:"— keines —"}},hotendHint:{t:0,b:{t:2,i:[{t:3,v:"Erwartet ~"},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},startFlow:{t:0,b:{t:2,i:[{t:3}],s:"Startfluss (mm³/s)"}},endFlow:{t:0,b:{t:2,i:[{t:3}],s:"Endfluss (mm³/s)"}},stepFlow:{t:0,b:{t:2,i:[{t:3}],s:"Schritt (mm³/s)"}},samples:{t:0,b:{t:2,i:[{t:3}],s:"Messungen / Schritt"}},extrudePerStep:{t:0,b:{t:2,i:[{t:3}],s:"Extrusion / Schritt (mm)"}}},plan:{button:{t:0,b:{t:2,i:[{t:3}],s:"Plan anzeigen"}},title:{t:0,b:{t:2,i:[{t:3}],s:"Geplante Rampe"}},stepCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Schritte"}]}},totalExtrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm Filament"}]}},sgField:{t:0,b:{t:2,i:[{t:3,v:"StallGuard-Feld: "},{t:4,k:"field"}]}},sgFieldUnknown:{t:0,b:{t:2,i:[{t:3}],s:"Kein StallGuard-Feld für diesen Treiber bekannt"}},flowHead:{t:0,b:{t:2,i:[{t:3}],s:"Fluss (mm³/s)"}},feedrateHead:{t:0,b:{t:2,i:[{t:3}],s:"Vorschub (mm/min)"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Der Live-Test heizt das Hotend und extrudiert Filament, absichtlich bis zum Durchrutschen. Nur Vorschau — es läuft noch nichts."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Vor dem Start — Sicherheits-Checkliste"}},items:[{t:0,b:{t:2,i:[{t:3}],s:"Filament ist geladen und läuft frei nach."}},{t:0,b:{t:2,i:[{t:3}],s:"Die Düse ist frei — über dem Bett oder einem Abfallbehälter, nicht in der Luft über Bauteilen."}},{t:0,b:{t:2,i:[{t:3}],s:"Mir ist bewusst, dass dabei absichtlich etwas Filament abgeschliffen wird/durchrutscht."}},{t:0,b:{t:2,i:[{t:3}],s:"Ich bleibe während des gesamten Tests beim Drucker."}}],ack:{t:0,b:{t:2,i:[{t:3}],s:"Ich habe alles oben Genannte erledigt und der Drucker ist bereit"}},note:{t:0,b:{t:2,i:[{t:3}],s:"Der Durchlauf wird während des Druckens verweigert; das Heizelement wird am Ende automatisch ausgeschaltet."}}},run:{button:{t:0,b:{t:2,i:[{t:3}],s:"Live-Test starten"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Läuft… (heizt + extrudiert)"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Den Live-Max-Flow-Test starten?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Dies heizt das Hotend auf "},{t:4,k:"temp"},{t:3,v:" °C und extrudiert bis zu "},{t:4,k:"mm"},{t:3,v:" mm Filament, mit steigender Rampe bis der Extruder durchrutscht."}]}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Jetzt starten"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Abbrechen"}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Verweigert: Der Drucker ist beschäftigt (druckt oder pausiert). Versuche es erneut, wenn er im Leerlauf ist."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Der Test ist fehlgeschlagen."}},noSg:{t:0,b:{t:2,i:[{t:3}],s:"Es wurden keine StallGuard-Messungen erfasst — das Schlupf-Ergebnis ist möglicherweise unzuverlässig. Wahrscheinlich muss das Live-SG-Feld des Treibers für dieses Modell angepasst werden."}},progress:{t:0,b:{t:2,i:[{t:3,v:"Schritt "},{t:4,k:"step"},{t:3,v:"/"},{t:4,k:"total"},{t:3,v:" — "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},starting:{t:0,b:{t:2,i:[{t:3}],s:"Heize / starte…"}},abort:{t:0,b:{t:2,i:[{t:3}],s:"Lauf abbrechen"}},cancelling:{t:0,b:{t:2,i:[{t:3}],s:"Breche ab…"}},cancelled:{t:0,b:{t:2,i:[{t:3}],s:"Lauf abgebrochen — die Heizung wurde ausgeschaltet."}},reattached:{t:0,b:{t:2,i:[{t:3}],s:"Wieder verbunden: dieses Ergebnis wurde fertig, während die Seite weg war."}},failed:{t:0,b:{t:2,i:[{t:3}],s:"Max-Flow-Lauf fehlgeschlagen."}},abortNote:{t:0,b:{t:2,i:[{t:3}],s:"Abbrechen schaltet die Heizung immer aus."}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Ergebnis"}},maxFlow:{t:0,b:{t:2,i:[{t:3}],s:"Maximal gehaltener Fluss"}},slipAt:{t:0,b:{t:2,i:[{t:3,v:"Durchrutschen erkannt bei "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},noSlip:{t:0,b:{t:2,i:[{t:3}],s:"Kein Durchrutschen bis zum höchsten getesteten Fluss"}},reason:{t:0,b:{t:2,i:[{t:3}],s:"Detail"}},recommendTitle:{t:0,b:{t:2,i:[{t:3}],s:"Vorgeschlagene Slicer-Werte (max volumetric speed)"}},conservative:{t:0,b:{t:2,i:[{t:3}],s:"Konservativ (80 %)"}},balanced:{t:0,b:{t:2,i:[{t:3}],s:"Ausgewogen (90 %)"}},units:{t:0,b:{t:2,i:[{t:3}],s:"mm³/s"}}},states:{loadingHotends:{t:0,b:{t:2,i:[{t:3}],s:"Hotends werden geladen…"}}}}};export{e as default};
